vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec3 reta = texture(sampler_main, vUv);
ret = reta;
//ret = sqrt(ret)*1;
//ret += GetBlur2(vUv);
ret -= GetBlur1(vUv)*0.5;

ret *= 2;

vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*roam_cos.y && ret.x<= q23*roam_sin.x)ret.z -= (noise9).x*.5;
if(ret.y> q25*roam_sin.x && ret.y<= q22*roam_cos.x)ret.x -= (noise9).y*.5;
if(ret.z> q24*roam_cos.x && ret.z<= q21*roam_sin.y)ret.y -= (noise9).z*.5;

  fragColor = ret;
}
